#!/usr/bin/env python3
"""Regenerate ALIGNED mamba-greedy K=8 targets for the cached XL prompts.

The XL cache has real-corpus targets (MISALIGNED — the frozen SSM context encodes
what mamba GENERATES, not arbitrary corpus text; CE can't overfit them). This
replaces the targets with mamba's own greedy continuation (the aligned, fittable
task that n=251 proved the denoiser learns), keeping the already-extracted contexts.

Reads:  mctx_xl_cache.jsonl (prompt_ids, per_layer_b16, ssm_b16, final_b16, ...)
Writes: greedy_xl_cache.jsonl (same + greedy target_ids), incremental/resumable.
"""
import json, os, sys, time, threading, urllib.request
from concurrent.futures import ThreadPoolExecutor

SC = os.path.dirname(os.path.abspath(__file__))
SRC = os.path.join(SC, "mctx_xl_cache.jsonl")
OUT = os.path.join(SC, "greedy_xl_cache.jsonl")
URL = "https://gwarm---gnosis-openai-mesh-6ptd7xm6fq-uc.a.run.app/debug/forward"
UA = "Mozilla/5.0 (Macintosh; Intel Mac OS X 10_15_7)"
K = 8
N_TARGET = int(sys.argv[1]) if len(sys.argv) > 1 else 2000
WORKERS = 8

_lock = threading.Lock()


def argmax_next(tokens, to=120):
    body = json.dumps({"tokens": tokens}).encode()
    req = urllib.request.Request(URL, data=body,
                                 headers={"content-type": "application/json", "User-Agent": UA})
    for attempt in range(5):
        try:
            with urllib.request.urlopen(req, timeout=to) as r:
                d = json.load(r)
            return int(d["argmax"]), int(d.get("nan_count", 0))
        except Exception as e:
            if attempt == 4:
                raise
            time.sleep(1.5)


def greedy_k(prompt_ids):
    seq = list(prompt_ids)
    gen = []
    for _ in range(K):
        nxt, nan = argmax_next(seq)
        if nan > 0:
            return None
        gen.append(nxt)
        seq.append(nxt)
    return gen


def main():
    # load source prompts (+ their contexts, which we keep verbatim)
    recs = []
    with open(SRC) as f:
        for line in f:
            line = line.strip()
            if line:
                recs.append(json.loads(line))
    recs = recs[:N_TARGET]
    # resume: skip keys already done
    done = set()
    if os.path.exists(OUT):
        with open(OUT) as f:
            for line in f:
                try:
                    done.add(json.loads(line)["key"])
                except Exception:
                    pass
    todo = [r for r in recs if r.get("key") not in done]
    print(f"[greedy] source={len(recs)} done={len(done)} todo={len(todo)}", flush=True)
    outf = open(OUT, "a")
    cnt = [len(done)]

    def work(r):
        try:
            g = greedy_k(r["prompt_ids"])
        except Exception as e:
            return ("err", str(e)[:40])
        if g is None:
            return ("nan", r.get("key"))
        rec = {"key": r["key"], "prompt_ids": r["prompt_ids"], "target_ids": g,
               "per_layer_b16": r["per_layer_b16"], "ssm_b16": r["ssm_b16"], "final_b16": r["final_b16"]}
        with _lock:
            outf.write(json.dumps(rec) + "\n")
            outf.flush()
            cnt[0] += 1
            if cnt[0] % 100 == 0:
                print(f"  [greedy] {cnt[0]}/{len(recs)}", flush=True)
        return ("ok", None)

    t0 = time.time()
    with ThreadPoolExecutor(max_workers=WORKERS) as ex:
        for _ in ex.map(work, todo):
            pass
    outf.close()
    print(f"[greedy] done {cnt[0]}/{len(recs)} in {time.time()-t0:.0f}s -> {OUT}", flush=True)


if __name__ == "__main__":
    main()
